import numpy as np
from collections import defaultdict

class InvertedIndex:
    def __init__(self):
        self.index = defaultdict(set)

    def add_document(self, doc_id, text: str):
        tokens = text.lower().split()
        for token in tokens:
            self.index[token].add(doc_id)

    def search(self, query: str):
        tokens = query.lower().split()
        if not tokens:
            return set()
        result = self.index.get(tokens[0], set()).copy()
        for token in tokens[1:]:
            result &= self.index.get(token, set())
        return result


class LSHIndex:
    def __init__(self, dim: int, num_hashes: int = 8, seed: int = 42):
        self.dim = dim
        self.num_hashes = num_hashes
        rng = np.random.RandomState(seed)
        self.hyperplanes = rng.randn(num_hashes, dim)
        self.buckets = defaultdict(list)  # hash_key -> [(vector, doc_id)]

    def _hash(self, vector):
        projections = self.hyperplanes @ np.asarray(vector)
        bits = (projections >= 0).astype(int)
        return ''.join(map(str, bits))

    def add(self, vector, doc_id):
        h = self._hash(vector)
        self.buckets[h].append((np.asarray(vector, dtype=float), doc_id))

    def query(self, vector, top_k: int = 5):
        vector = np.asarray(vector, dtype=float)
        h = self._hash(vector)
        candidates = self.buckets.get(h, [])
        if not candidates:
            return []
        scored = []
        norm_q = np.linalg.norm(vector)
        if norm_q == 0:
            return [doc_id for _, doc_id in candidates[:top_k]]
        for cand_vec, doc_id in candidates:
            norm_c = np.linalg.norm(cand_vec)
            if norm_c == 0:
                sim = 0.0
            else:
                sim = float(np.dot(vector, cand_vec) / (norm_q * norm_c))
            scored.append((sim, doc_id))
        scored.sort(key=lambda x: x[0], reverse=True)
        return [doc_id for _, doc_id in scored[:top_k]]


def symmetric_quantize(tensor, num_bits: int = 8):
    tensor = np.asarray(tensor, dtype=float)
    max_abs = np.max(np.abs(tensor))
    qmax = (1 << (num_bits - 1)) - 1  # 127 for 8-bit
    if max_abs == 0:
        return np.zeros_like(tensor, dtype=int), 1.0
    scale = max_abs / qmax
    quantized = np.round(tensor / scale).astype(int)
    quantized = np.clip(quantized, -qmax, qmax)
    return quantized, float(scale)


def dequantize(quantized_values, scale: float):
    return np.asarray(quantized_values, dtype=float) * scale

